#include <stdio.h>

int main(void) {
    size_t count;
    if (scanf("%zu", &count) != 1 || count > 20) return 1;
    FILE *stream = tmpfile();
    if (stream == NULL) return 1;
    for (size_t i = 0; i < count; ++i) { int value; if (scanf("%d", &value) != 1 || fprintf(stream, "%d\n", value) < 0) { fclose(stream); return 1; } }
    rewind(stream);
    long long sum = 0;
    for (size_t i = 0; i < count; ++i) { int value; if (fscanf(stream, "%d", &value) != 1) { fclose(stream); return 1; } sum += value; }
    if (fclose(stream) != 0) return 1;
    printf("%lld\n", sum);
    return 0;
}
